"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
  setTotalSteps: React.Dispatch<React.SetStateAction<number>>
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Step item context – tracks the index of each <StepperItem>
// ---------------------------------------------------------------------------

type StepperItemContextProps = {
  step: number
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

function Stepper({
  defaultValue = 0,
  value,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  defaultValue?: number
  value?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [_activeStep, _setActiveStep] = React.useState(defaultValue)
  const [totalSteps, setTotalSteps] = React.useState(0)

  const activeStep = value ?? _activeStep
  const setActiveStep = React.useCallback(
    (step: number) => {
      if (onValueChange) {
        onValueChange(step)
      } else {
        _setActiveStep(step)
      }
    },
    [onValueChange]
  )

  const contextValue = React.useMemo<StepperContextProps>(
    () => ({
      activeStep,
      setActiveStep,
      orientation,
      totalSteps,
      setTotalSteps,
    }),
    [activeStep, setActiveStep, orientation, totalSteps, setTotalSteps]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex data-[orientation=horizontal]:flex-col data-[orientation=vertical]:flex-row data-[orientation=vertical]:gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperList – wraps the step indicators / triggers
// ---------------------------------------------------------------------------

function StepperList({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal"
          ? "flex-row items-center"
          : "flex-col items-stretch",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperItem – wraps a single step indicator (trigger + labels)
// ---------------------------------------------------------------------------

let stepCounter = 0

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep, orientation, setTotalSteps } = useStepper()

  React.useEffect(() => {
    setTotalSteps((prev) => Math.max(prev, step + 1))
  }, [step, setTotalSteps])

  const status =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-status={status}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex items-center",
          orientation === "horizontal" ? "flex-1 flex-row" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger – the clickable circle / indicator for a step
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> & { asChild?: boolean }) {
  const { activeStep, setActiveStep } = useStepper()
  const { step } = useStepperItem()

  const status =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "inactive"

  return (
    <button
      data-slot="stepper-trigger"
      role="tab"
      type="button"
      aria-selected={status === "active"}
      data-status={status}
      onClick={() => setActiveStep(step)}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        status === "active" &&
          "border-primary bg-primary text-primary-foreground",
        status === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        status === "inactive" &&
          "border-muted-foreground/25 bg-transparent text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (status === "completed" ? (
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="16"
            height="16"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <path d="M20 6 9 17l-5-5" />
          </svg>
        ) : (
          step + 1
        ))}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn(
        "text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator – line between steps
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "bg-muted-foreground/25 transition-colors group-data-[status=completed]/stepper-item:bg-primary",
        orientation === "horizontal"
          ? "mx-2 h-0.5 flex-1"
          : "my-2 ml-4 w-0.5 self-stretch min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent – the content panel shown for the active step
// ---------------------------------------------------------------------------

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      role="tabpanel"
      data-step={step}
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
}

