  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep, orientation, setTotalSteps } = useStepper()

  React.useEffect(() => {
    setTotalSteps((prev) => Math.max(prev, step + 1))
  }, [step, setTotalSteps])

  const status =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, status }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-status={status}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex items-center",
          orientation === "horizontal" ? "flex-1 flex-row" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
