// ---------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator – line between steps
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { status } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-status={status}
      className={cn(
        "transition-colors",
        status === "completed"
          ? "bg-primary"
          : "bg-muted-foreground/25",
        orientation === "horizontal"
          ? "mx-2 h-0.5 flex-1"
          : "my-2 ml-4 w-0.5 self-stretch min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent – the content panel shown for the active step
// ---------------------------------------------------------------------------

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      role="tabpanel"
      data-step={step}
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
}

