"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
  setTotalSteps: React.Dispatch<React.SetStateAction<number>>
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Step item context – tracks the index of each <StepperItem>
// ---------------------------------------------------------------------------

type StepperItemContextProps = {
  step: number
  status: "completed" | "active" | "inactive"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />.")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

function Stepper({
  defaultValue = 0,
  value,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  defaultValue?: number
  value?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [_activeStep, _setActiveStep] = React.useState(defaultValue)
  const [totalSteps, setTotalSteps] = React.useState(0)

  const activeStep = value ?? _activeStep
  const setActiveStep = React.useCallback(
    (step: number) => {
      if (onValueChange) {
        onValueChange(step)
      } else {
        _setActiveStep(step)
      }
    },
    [onValueChange]
  )

  const contextValue = React.useMemo<StepperContextProps>(
    () => ({
      activeStep,
      setActiveStep,
      orientation,
      totalSteps,
      setTotalSteps,
    }),
    [activeStep, setActiveStep, orientation, totalSteps]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex data-[orientation=horizontal]:flex-col data-[orientation=vertical]:flex-row data-[orientation=vertical]:gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

